    const doubled = [...items, ...items];

    onMount(async () => {
        hljs.highlightElement(codeBlock);

        updatePadding();
        roFS = new ResizeObserver(updatePadding);
        roFS.observe(headerTOP);
        window.addEventListener('resize', updatePadding);
    });

    onDestroy(() => {
        roFS?.disconnect();
        if (typeof window !== 'undefined') {
            window.removeEventListener(
                'resize',
                updatePadding
            );
        }
    });
</script>

<header bind:this={headerTOP} class="bg-[#f6f8fa] w-full px-7.5 py-3.75 border-b-2 border-b-[#d5dce3] z-900 fixed top-0 left-0 flex items-center justify-start">
