        <button class="w-fit h-fit p-0 font-sans cursor-pointer text-[15px] text-[#59636e] transition-all duration-300 ease-in-out focus:outline-none focus:ring-0 focus:border-0 hover:text-[#1f2328]" onclick={() => window.location.href="/login"}>Masuk</button>
        <button class="group w-fit pl-3.75 pr-3.75 h-full border-[1.5px] border-[#d5dce3] rounded-[5px] bg-transparent font-sans cursor-pointer text-[15px] text-[#59636e] transition-all duration-300 ease-in-out flex items-center justify-center gap-1.5 hover:text-[#1f2328] hover:border-[#1f2328]" onclick={() => window.location.href="/register"}><svg class="w-2.5 fill-[#59636e] transition-all duration-300 ease-in-out group-hover:fill-[#1f2328]" version="1.1" xmlns="http://www.w3.org/2000/svg" width="10" height="10"><path d="M0 0 C0.66 0 1.32 0 2 0 C2 0.66 2 1.32 2 2 C1.34 2 0.68 2 0 2 C0 1.34 0 0.68 0 0 Z " transform="translate(2,8)"/><path d="M0 0 C0.66 0 1.32 0 2 0 C2 0.66 2 1.32 2 2 C1.34 2 0.68 2 0 2 C0 1.34 0 0.68 0 0 Z " transform="translate(4,6)"/><path d="M0 0 C0.66 0 1.32 0 2 0 C2 0.66 2 1.32 2 2 C1.34 2 0.68 2 0 2 C0 1.34 0 0.68 0 0 Z " transform="translate(6,4)"/><path d="M0 0 C0.66 0 1.32 0 2 0 C2 0.66 2 1.32 2 2 C1.34 2 0.68 2 0 2 C0 1.34 0 0.68 0 0 Z " transform="translate(4,2)"/><path d="M0 0 C0.66 0 1.32 0 2 0 C2 0.66 2 1.32 2 2 C1.34 2 0.68 2 0 2 C0 1.34 0 0.68 0 0 Z " transform="translate(2,0)"/></svg>Daftar</button>
    </div>

    <div class="w-fit h-8.25 hidden items-center justify-center absolute right-7.5 gap-3 max-sm:flex">
